fun solve(grid: Array<Array<Long>>, k: Long): Long {
    var count = 0L
    val m = grid.size
    if (m == 0) return 0L
    val n = grid[0].size
    val queue = ArrayDeque<Pair<Int, Int>>()
    val directions = listOf(0 to 1, 0 to -1, 1 to 0, -1 to 0)

    for (i in 0 until m) {
        for (j in 0 until n) {
            if (grid[i][j] > 0) {
                var total = 0L
                queue.add(i to j)
                total += grid[i][j]
                grid[i][j] = 0

                while (queue.isNotEmpty()) {
                    val (x, y) = queue.removeFirst()
                    for ((dx, dy) in directions) {
                        val nx = x + dx
                        val ny = y + dy
                        if (nx in 0 until m && ny in 0 until n && grid[nx][ny] > 0) {
                            total += grid[nx][ny]
                            grid[nx][ny] = 0
                            queue.add(nx to ny)
                        }
                    }
                }

                if (total % k == 0L) {
                    count++
                }
            }
        }
    }

    return count
}
